                        void a.content.offsetHeight;
                        a.content.style.height = '1px';
                        a.content.style.opacity = a.closedContentOpacity;
                        if (a.textEl) a.textEl.style.opacity = a.closedTextOpacity;
                        applyIconState(a, false);
