                a.wrapper.addEventListener('click', toggle);
                a.wrapper.addEventListener('keydown', function(e) {
                    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggle(e); }
                });
            });
        });
    }

    init();
    window.addEventListener('load', init);
